import numpy as np

def validate(a):
    if a.ndim != 1 or a.dtype != np.float64:
        raise ValueError("expected 1d float64")
    print("ok", a.size)

validate(np.array([0.1, 0.2], dtype=np.float64))
try:
    validate(np.array([1, 2]))
except ValueError as e:
    print("err", e)

